  flights:{eyebrow:'Network operations',title:'Flight management',text:'Control schedules, aircraft, live status, routes and available cargo capacity.',singular:'Flight',prefix:'AAC',columns:[['id','Flight'],['route','Route'],['aircraft','Aircraft'],['departure','Departure'],['available','Space available'],['utilization','Utilization'],['status','Status']],fields:[['route','Route','text'],['aircraft','Aircraft','select',['Boeing 737-800F','Boeing 747-400F','Boeing 777F','Airbus A330F']],['departure','Departure','text'],['capacity','Total capacity','text'],['available','Available space','text'],['utilization','Utilization','text'],['status','Flight status','select',['Scheduled','On time','Boarding','Delayed','Cancelled']]]},
  stations:{eyebrow:'Airport network',title:'Station management',text:'Maintain airports, locations, local management and operational contact details.',singular:'Station',prefix:'STN',columns:[['id','Airport code'],['city','City'],['state','State'],['country','Country'],['manager','Manager'],['phone','Contact'],['status','Status']],fields:[['id','Airport code','text'],['city','City','text'],['state','State','text'],['country','Country','text'],['manager','Station manager','text'],['phone','Contact number','text'],['status','Status','select',['Active','Inactive']]]},
  rates:{eyebrow:'Commercial control',title:'Rate management',text:'Configure route pricing, weight slabs, fuel surcharge, taxes and special customer rates.',singular:'Rate',prefix:'RATE',columns:[['route','Route'],['slab','Weight slab'],['base','Base rate'],['fuel','Fuel'],['gst','GST'],['seasonal','Seasonal'],['customer','Customer'],['status','Status']],fields:[['route','Airport-to-airport route','text'],['slab','Weight slab','select',['0–44 kg','45–99 kg','100–499 kg','500–999 kg','1000+ kg']],['base','Base rate','text'],['fuel','Fuel surcharge','text'],['gst','GST','text'],['seasonal','Seasonal charge','text'],['customer','Customer rate','text'],['status','Status','select',['Active','Inactive']]]},
  charges:{eyebrow:'Commercial configuration',title:'Freight charge controls',text:'Control the minimum weight, base freight and every surcharge used by the client New Shipment calculator. Enter 0 to disable a charge.',singular:'Charge profile',prefix:'CHG',columns:[['name','Profile'],['baseRatePerKg','Base ₹/kg'],['minimumChargeableWeight','Minimum kg'],['xrayRatePerKg','X-ray ₹/kg'],['commoditySurcharge','Commodity'],['originStationCharge','Origin'],['destinationStationCharge','Destination']],fields:[['name','Profile name','text'],['baseRatePerKg','Base freight rate ₹/kg','number'],['minimumChargeableWeight','Minimum chargeable weight kg','number'],['volumetricDivisor','Volumetric divisor','number'],['sectorSurcharge','Sector surcharge ₹','number'],['flightSurcharge','Flight surcharge ₹','number'],['commoditySurcharge','Commodity surcharge ₹','number'],['originStationCharge','Origin station charge ₹','number'],['destinationStationCharge','Destination station charge ₹','number'],['xrayRatePerKg','X-ray rate ₹/kg','number'],['handleWithCareCharge','Handle with care ₹','number'],['priorityHandlingCharge','Priority handling ₹','number'],['temperatureControlCharge','Temperature control ₹','number']]},
